    Fits lightcurves using SNCOSMO (using SALT2 defaultwise)
    with redshift constrained by catalog matching results.

    config example:
    {
            "model": "salt2",
            "jd_reject_sigma": 3,
            "plot_props": {
                    "tags": ["SALT", "SNCOSMO"],
                    "file_name": {
                            "format_str": "%s_%s_%s_fit.svg",
                            "arg_keys": ["stock", "model", "catalog"]
                    },
                    "title": {
                            "format_str": "%s %s lightcurve fit",
                            "arg_keys": ["stock", "catalog"]
                    },
                    "fig_text": {
                            "format_str": "%s %s %s
chisq %.2f
ndof %s
fit_ok %s",
                            "arg_keys": ["stock", "model", "catalog", "chisq", "ndof", "fit_ok"]
                    },
                    "width": 10,
                    "height": 6,
                    "id_mapper": "ZTFIdMapper",
                    "disk_save": "/path/to/plots/dir/"
            },
            "t2_dependency": [
                    {
                            "unit": "T2NEDTap",
                            "link_override": {'filter': 'PPSFilter', 'sort': 'jd', 'select': 'first'}
                    }
            ]
    }

:returns: example of a match in SDSS but not in NED:

{
    'SDSS_spec': {
        'z': 0.08820018172264099,
        'bptclass': 2.0,
        'subclass': '',
        'dist2transient': 1.841666956181802e-09}
    },
    'NED': False
}

Note that, when a match is found, the distance of the lightcurve object
to the catalog counterpart is also returned as the 'dist2transient' key.

# Require a high RB score.
# Generally requires >0.2, but is more stringent if close to a bright catalogued star.
real = False;
if (rbscore > 0.2) {
        real = True;
}
if (rbscore < 0.35) {
        if (neargaia < 1.0 and neargaia > 0. and maggaia < 17.0 and maggaia > 0.) {real = False;}
        if (distpsnr1 < 1.0 and (srmag1 > 0 and srmag1 < 17.0 or simag1 > 0 and simag1 < 17.0 or szmag1 > 0 and szmag1 < 16.5) and sgscore1 > 0.49) {real = False;}
}
if (rbscore < 0.45) {
        if (neargaia < 1.5 and neargaia > 0. and maggaia < 15.5 and maggaia > 0.) {real = False;}
        if (distpsnr1 < 1.5 and (srmag1 > 0 and srmag1 < 15.5 or simag1 > 0 and simag1 < 15.5 or szmag1 > 0 and szmag1 < 15.0) and sgscore1 > 0.49) {real = False;}
}
if (drb < 0.5) {
        if (distpsnr1 < 3.0 and ps1mag < 16 and age > 90) { real = False; }
        if (distpsnr1 < 1.1 and ps1mag < 18 and age > 90) { real = False; }
}
if (drb < 0.8) {
        if (distpsnr1 < 1.5 and ps1mag < 15.5 and age > 90) { real = False; }
        if (distpsnr1 < 0.8 and ps1mag < 17.5 and age > 90) { real = False; }
}

